import { render, screen, userEvent } from "test_utils";
import Accordion from ".";

describe("accordion", () => {
  it("properly expands and collapses", async () => {
    const user = userEvent.setup();
    render(
      <Accordion title="collapsed" toggledTitle="expanded">
        accordion content
      </Accordion>,
    );
    await user.click(screen.getByDataCy("accordion-toggle"));
    expect(screen.getByText("expanded")).toBeInTheDocument();
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "true",
    );
    await user.click(screen.getByDataCy("accordion-toggle"));
    expect(screen.getByText("collapsed")).toBeInTheDocument();
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "false",
    );
  });

  it("should be expanded if defaultOpen is true", () => {
    render(
      <Accordion defaultOpen title="accordion title">
        accordion content
      </Accordion>,
    );
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "true",
    );
  });

  it("calls onToggle when accordion is toggled", async () => {
    const user = userEvent.setup();
    const onToggle = vi.fn();
    render(
      <Accordion onToggle={onToggle} title="accordion title">
        accordion content
      </Accordion>,
    );
    await user.click(screen.getByDataCy("accordion-toggle"));
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "true",
    );
    expect(onToggle).toHaveBeenCalledTimes(1);
    await user.click(screen.getByDataCy("accordion-toggle"));
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "false",
    );
    expect(onToggle).toHaveBeenCalledTimes(2);
  });

  it("uses titleTag if provided", () => {
    const titleTag = () => <span data-cy="my-custom-tag" />;
    render(
      <Accordion title="accordion title" titleTag={titleTag}>
        accordion content
      </Accordion>,
    );
    expect(screen.getByDataCy("my-custom-tag")).toBeInTheDocument();
  });
  it("when controlled, accordion should be open if open prop is true", () => {
    const { rerender } = render(
      <Accordion open title="accordion title">
        accordion content
      </Accordion>,
    );
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "true",
    );
    rerender(
      <Accordion open={false} title="accordion title">
        accordion content
      </Accordion>,
    );
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "false",
    );
  });
  it("when controlled, accordion should call a callback when the user toggles it open or closed", async () => {
    const onToggle = vi.fn();
    const user = userEvent.setup();
    render(
      <Accordion onToggle={onToggle} open title="accordion title">
        accordion content
      </Accordion>,
    );
    expect(screen.getByDataCy("accordion-collapse-container")).toHaveAttribute(
      "aria-expanded",
      "true",
    );
    await user.click(screen.getByDataCy("accordion-toggle"));
    expect(onToggle).toHaveBeenCalledTimes(1);
  });
});

import { renderWithRouterMatch, screen, userEvent } from "test_utils";
import Pagination from ".";

describe("pagination", () => {
  it("should render the correct page count given total results and page size", () => {
    const { rerender } = renderWithRouterMatch(
      <Pagination currentPage={0} pageSize={5} totalResults={10} />,
    );
    expect(screen.getByText("1 / 2")).toBeInTheDocument();
    rerender(<Pagination currentPage={0} pageSize={10} totalResults={10} />);
    expect(screen.getByText("1 / 1")).toBeInTheDocument();
    rerender(<Pagination currentPage={0} pageSize={10} totalResults={100} />);
    expect(screen.getByText("1 / 10")).toBeInTheDocument();
    rerender(<Pagination currentPage={0} pageSize={10} totalResults={0} />);
    expect(screen.getByText("0 / 0")).toBeInTheDocument();
  });
  it("shold disable the previous page if on the first page", () => {
    const { router } = renderWithRouterMatch(
      <Pagination currentPage={0} pageSize={5} totalResults={10} />,
    );
    expect(router.state.location.search).toBe("");
    expect(screen.queryByDataCy("prev-page-button")).toHaveAttribute(
      "aria-disabled",
      "true",
    );
  });
  it("should disable the next page if on the last page", () => {
    const { router } = renderWithRouterMatch(
      <Pagination currentPage={1} pageSize={5} totalResults={10} />,
    );
    expect(router.state.location.search).toBe("");
    expect(screen.queryByDataCy("next-page-button")).toHaveAttribute(
      "aria-disabled",
      "true",
    );
  });
  it("paginating forward should update the url with the new page number by default", async () => {
    const user = userEvent.setup();
    const { router } = renderWithRouterMatch(
      <Pagination currentPage={0} pageSize={5} totalResults={10} />,
    );

    expect(router.state.location.search).toBe("");
    await user.click(screen.getByDataCy("next-page-button"));
    expect(router.state.location.search).toBe("?page=1");
  });
  it("paginating backward should update the url with the new page number by default", async () => {
    const user = userEvent.setup();
    const { router } = renderWithRouterMatch(
      <Pagination currentPage={1} pageSize={5} totalResults={10} />,
    );

    expect(router.state.location.search).toBe("");
    await user.click(screen.getByDataCy("prev-page-button"));
    expect(router.state.location.search).toBe("?page=0");
  });

  it("should call the onChange callback when the page changes", async () => {
    const user = userEvent.setup();
    const onChange = vi.fn();
    renderWithRouterMatch(
      <Pagination
        currentPage={0}
        onChange={onChange}
        pageSize={5}
        totalResults={10}
      />,
    );
    await user.click(screen.getByDataCy("next-page-button"));
    expect(onChange).toHaveBeenCalledWith(1);
  });
  it("should disable pagination if there  is only one page", () => {
    renderWithRouterMatch(
      <Pagination currentPage={0} pageSize={5} totalResults={5} />,
    );
    expect(screen.queryByDataCy("prev-page-button")).toHaveAttribute(
      "aria-disabled",
      "true",
    );
    expect(screen.queryByDataCy("next-page-button")).toHaveAttribute(
      "aria-disabled",
      "true",
    );
  });
  it("should disable pagination if there are no pages", () => {
    renderWithRouterMatch(
      <Pagination currentPage={0} pageSize={5} totalResults={5} />,
    );
    expect(screen.queryByDataCy("prev-page-button")).toHaveAttribute(
      "aria-disabled",
