import { useRef, useState } from "react";
import styled from "@emotion/styled";
import { GuideCue, GuideCueProps } from "@leafygreen-ui/guide-cue";
import { palette } from "@leafygreen-ui/palette";
import { differenceInDays } from "date-fns";
import Cookies from "js-cookie";
import { size } from "../../constants/tokens";
import Icon from "../Icon";

type Props = {
  activeDays?: number;
  cookieName: string;
  loading?: boolean;
};

/**
 * ExpiringAnnouncementTooltip displays a clickable info icon with a popover.
 * On first view, the popover opens automatically. Once dismissed, a cookie is set
 * and the popover stays closed on future visits. The info icon remains visible
 * for `activeDays` (default 8) after first dismissal, then disappears entirely.
 * @param props - React props
 * @param props.activeDays - number of days the info icon will persist after the tooltip is first viewed
 * @param props.cookieName - cookie associated with the view state
 * @param props.loading - whether data present in the tooltip is loading, helps avoid flickering tooltip
 * @returns React component
 */
export const ExpiringAnnouncementTooltip: React.FC<
  Props & Pick<GuideCueProps, "children" | "title" | "tooltipAlign">
> = ({ activeDays = 8, cookieName, loading = false, ...guideCueProps }) => {
  const now = new Date();
  const infoRef = useRef(null);

  const seenTooltipCookie: string | undefined = Cookies.get(cookieName);
  const neverSeenTooltip = !seenTooltipCookie;
  const seenTooltipDate = seenTooltipCookie ? new Date(seenTooltipCookie) : now;

  const [open, setOpen] = useState(neverSeenTooltip);

  const close = () => {
    setOpen(false);

    if (neverSeenTooltip) {
      Cookies.set(cookieName, seenTooltipDate.toString(), { expires: 365 });
    }
  };

  return !loading &&
    (neverSeenTooltip ||
      differenceInDays(now, seenTooltipDate) < activeDays) ? (
    <>
      <IconContainer ref={infoRef}>
        <Icon
          data-cy="announcement-tooltip-trigger"
          fill={palette.gray.dark2}
          glyph="InfoWithCircle"
          onClick={() => setOpen((o) => !o)}
        />
      </IconContainer>
      <GuideCue
        currentStep={1}
        numberOfSteps={1}
        onDismiss={close}
        onPrimaryButtonClick={close}
        open={open}
        refEl={infoRef}
        setOpen={setOpen}
        {...guideCueProps}
      />
    </>
  ) : null;
};

const IconContainer = styled.div`
  cursor: pointer;
  padding-left: ${size.xxs};
`;

import Cookie from "js-cookie";
import { MockInstance } from "vitest";
import {
  renderWithRouterMatch as render,
  screen,
  stubGetClientRects,
  userEvent,
  waitFor,
} from "../../test_utils";
import { ExpiringAnnouncementTooltip } from ".";

vi.mock("js-cookie");
const mockedGet = vi.spyOn(Cookie, "get") as MockInstance;
const mockedSet = vi.spyOn(Cookie, "set") as MockInstance;

describe("ExpiringAnnouncementTooltip", () => {
  beforeAll(() => {
    stubGetClientRects();
  });

  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.clearAllMocks();
    vi.useRealTimers();
  });

  const fakeDate = new Date(2025, 1, 1);
  const oneDayLater = new Date(2025, 1, 2);
  const twoWeeksLater = new Date(2025, 1, 15);

  describe("upon first view of tooltip", () => {
    it("renders with guide cue open if user has never seen it", async () => {
      render(
        <ExpiringAnnouncementTooltip
          cookieName="TEST_COOKIE"
          title="New Release"
        >
          Try out this feature
        </ExpiringAnnouncementTooltip>,
      );
      await waitFor(() => {
        expect(screen.getByText("New Release")).toBeVisible();
      });
    });

    it("does not render if loading", async () => {
      render(
        <ExpiringAnnouncementTooltip
          cookieName="TEST_COOKIE"
          loading
          title="New Release"
        >
          Try out this feature
        </ExpiringAnnouncementTooltip>,
      );
      expect(screen.queryByText("New Release")).not.toBeInTheDocument();
    });

    it("closes the icon when the icon is clicked", async () => {
      const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime });
      render(
        <ExpiringAnnouncementTooltip
          cookieName="TEST_COOKIE"
          title="New Release"
        >
          Try out this feature
        </ExpiringAnnouncementTooltip>,
      );

      await waitFor(() => {
        expect(screen.getByText("New Release")).toBeVisible();
      });
      await user.click(screen.getByDataCy("announcement-tooltip-trigger"));
      await waitFor(() => {
        expect(screen.queryByText("New Release")).not.toBeVisible();
      });
    });

    it("sets a cookie with the date and expiration upon close", async () => {
      const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime });
      vi.setSystemTime(fakeDate);

      render(
        <ExpiringAnnouncementTooltip
          cookieName="TEST_COOKIE"
          title="New Release"
        >
          Try out this feature
        </ExpiringAnnouncementTooltip>,
      );
      await waitFor(() => {
        expect(screen.getByText("New Release")).toBeVisible();
      });
      await user.click(screen.getByRole("button", { name: "Got it" }));

      await waitFor(() => {
        expect(screen.queryByText("New Release")).not.toBeVisible();
      });

      expect(mockedSet).toHaveBeenCalledExactlyOnceWith(
        "TEST_COOKIE",
        fakeDate.toString(),
        { expires: 365 },
      );
    });
  });

  describe("when user has already seen tooltip within one week", () => {
    it("doesn't open tooltip upon render", async () => {
      mockedGet.mockReturnValue(fakeDate.toString());
      vi.setSystemTime(oneDayLater);

      render(
        <ExpiringAnnouncementTooltip
          cookieName="TEST_COOKIE"
          title="New Release"
        >
          Try out this feature
        </ExpiringAnnouncementTooltip>,
      );
      expect(mockedGet).toHaveBeenCalledOnce();
      expect(screen.queryByText("New Release")).not.toBeInTheDocument();
    });

    it("opens the tooltip when the button is clicked and doesn't update the cookie date on close", async () => {
      const user = userEvent.setup({ advanceTimers: vi.advanceTimersByTime });
      mockedGet.mockReturnValue(fakeDate.toString());
      vi.setSystemTime(oneDayLater);

      render(
        <ExpiringAnnouncementTooltip
          cookieName="TEST_COOKIE"
          title="New Release"
        >
          Try out this feature
        </ExpiringAnnouncementTooltip>,
      );
      expect(mockedGet).toHaveBeenCalledOnce();
      expect(screen.queryByText("New Release")).not.toBeInTheDocument();

      await user.click(screen.getByDataCy("announcement-tooltip-trigger"));
      await waitFor(() => {
        expect(screen.getByText("New Release")).toBeVisible();
      });
      await user.click(screen.getByRole("button", { name: "Got it" }));
      await waitFor(() => {
        expect(screen.queryByText("New Release")).not.toBeInTheDocument();
      });
      expect(mockedSet).not.toHaveBeenCalled();
    });
  });

  describe("when user has seen tooltip two weeks ago", () => {
    it("does not show the popover icon", () => {
      mockedGet.mockReturnValue(fakeDate.toString());
      vi.setSystemTime(twoWeeksLater);

      render(
        <ExpiringAnnouncementTooltip
          cookieName="TEST_COOKIE"
          title="New Release"
        >
          Try out this feature
        </ExpiringAnnouncementTooltip>,
      );
      expect(
        screen.queryByLabelText("Info With Circle Icon"),
      ).not.toBeInTheDocument();
    });
  });
});

import { css } from "@emotion/react";
import styled from "@emotion/styled";
import { Badge, Variant } from "@leafygreen-ui/badge";
import { palette } from "@leafygreen-ui/palette";
import { taskStatusToCopy } from "../../../constants/task";
import { TaskStatus, TaskStatusUmbrella } from "../../../types/task";

const { purple, red, white } = palette;

interface BadgeColorProps {
  border?: string;
  fill?: string;
  text?: string;
}

const badgeWidthMaxContent = css`
  width: max-content;
`;

// only use for statuses whose color is not supported by leafygreen badge variants, i.e. SystemFailed, TestTimedOut, SetupFailed
const StyledBadge = styled(Badge)<BadgeColorProps>`
  ${({ border }) => border && `border-color: ${border} !important;`}
  ${({ fill }) => fill && `background-color: ${fill} !important;`}
  ${({ text }) => text && `color: ${text} !important;`}
  ${badgeWidthMaxContent}
`;

interface TaskStatusBadgeProps {
  taskCount?: number;
  status: TaskStatus | TaskStatusUmbrella | undefined;
}
const TaskStatusBadge: React.FC<TaskStatusBadgeProps> = ({
  status,
  taskCount,
}) => {
  if (!status) {
    return null;
  }

  const statusText = taskStatusToCopy[status] ?? status;

  const badgeCopy =
    taskCount === undefined ? statusText : `${taskCount} ${statusText}`;
  return (
    <StyledBadge
      key={status}
      data-cy="task-status-badge"
      variant={mapTaskStatusToBadgeVariant[status]}
      {...customBadgeColors(status)}
    >
      {badgeCopy}
    </StyledBadge>
  );
};

const mapTaskStatusToBadgeVariant: Record<string, Variant> = {
  [TaskStatus.Inactive]: Variant.LightGray,
  [TaskStatus.Unstarted]: Variant.LightGray,
  [TaskStatus.Undispatched]: Variant.LightGray,
  [TaskStatus.Blocked]: Variant.LightGray,
  [TaskStatus.Pending]: Variant.LightGray,
  [TaskStatus.Unscheduled]: Variant.LightGray,
  [TaskStatus.Aborted]: Variant.LightGray,
  [TaskStatus.Started]: Variant.Yellow,
  [TaskStatus.Dispatched]: Variant.Yellow,
  [TaskStatus.Failed]: Variant.Red,
  [TaskStatus.TestTimedOut]: Variant.Red,
  [TaskStatus.TaskTimedOut]: Variant.Red,
  [TaskStatus.Succeeded]: Variant.Green,
  [TaskStatus.WillRun]: Variant.DarkGray,
};
const customBadgeColors = (status: string) => {
  switch (status) {
    case TaskStatus.SetupFailed:
      return {
        border: purple.base,
        fill: purple.light2,
        text: purple.dark2,
      };
    case TaskStatus.SystemFailed:
    case TaskStatus.SystemUnresponsive:
    case TaskStatus.SystemTimedOut:
      return {
        border: purple.dark3,
        fill: purple.dark2,
        text: purple.light3,
      };
    case TaskStatus.KnownIssue:
      return {
        border: red.light2,
        fill: white,
        text: red.dark2,
      };
    default:
      return {};
  }
};

export default TaskStatusBadge;

