import type { StorybookConfig } from "@storybook/react-vite";

// Storybook requires using .ts extensions explicitly for imports.
export { previewHead } from "./preview-head.ts";

export const stories = ["../src/**/*.stories.@(js|jsx|ts|tsx)"];

export const addons: StorybookConfig["addons"] = [
  "@storybook/addon-docs",
  "@storybook/addon-links",
  "storybook-addon-apollo-client",
];

/**
 * Alias @emotion/server to @emotion/css to prevent LeafyGreen's emotion package
 * from pulling in SSR dependencies that use Node.js Buffer.
 * https://jira.mongodb.org/browse/EVG-17077
 * @internal
 */
export const viteFinal: StorybookConfig["viteFinal"] = (config) => {
  config.resolve = config.resolve ?? {};
  config.resolve.alias = {
    ...config.resolve.alias,
    "@emotion/server": "@emotion/css",
  };
  return config;
};

import { MockedProvider } from "@apollo/client/testing/react";
import LeafyGreenProvider from "@leafygreen-ui/leafygreen-provider";
import { Decorator, Parameters, Preview } from "@storybook/react-vite";
import { createMemoryRouter, RouterProvider } from "react-router-dom";

const parameters: Parameters = {
  actions: { argTypesRegex: "^on[A-Z].*" },
  apolloClient: {
    MockedProvider: ({ children }: { children: React.ReactNode }) => children,
  },
  controls: {
    matchers: {
      color: /(background|color)$/i,
      date: /Date$/,
    },
  },
};

const decorators: Decorator[] = [
  (Story) => (
    <LeafyGreenProvider>
      <Story />
    </LeafyGreenProvider>
  ),
  (
    Story,
    {
      parameters: {
        apolloClient: { MockedProvider: _, ...rest },
      },
    },
  ) => (
    <MockedProvider {...rest}>
      <Story />
    </MockedProvider>
  ),
  (Story, context) => {
    const { parameters: storyParameters } = context;
    const { reactRouter } = storyParameters;
    const { params, path, route } = reactRouter || {};
    const routes = [
      {
        path: path || "/",
        parameters: params || {},
        element: <Story />,
        errorElement: <div>Failed to render component.</div>,
      },
    ];
    const memoryRouter = createMemoryRouter(routes, {
      initialEntries: [route || "/"],
    });
    return <RouterProvider router={memoryRouter} />;
  },
];

const preview: Preview = {
  parameters,
  decorators,
};

export default preview;

import { type StorybookConfig } from "@storybook/react-vite";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

// Storybook requires using .ts extensions explicitly for imports.
export { addons, previewHead, stories, viteFinal } from "./main/index.ts";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

export const previewAnnotations: StorybookConfig["previewAnnotations"] = [
  join(__dirname, "preview", "index.tsx"),
];

export enum TestStatus {
  Fail = "fail",
  Skip = "skip",
  SilentFail = "silentfail",
  Pass = "pass",
}

