export const ALL_VALUE = "all";
const ALL_COPY = "All";
export interface TreeSelectProps {
  isVisible?: boolean;
  onChange: (s: string[]) => void;
  setOptionsLabel?: (v: string) => void;
  state: string[];
  tData: TreeDataEntry[];
  onReset?: () => void;
